USE moviedekho;

ON DUPLICATE KEY UPDATE title=VALUES(title), slug=VALUES(slug), genre=VALUES(genre), description=VALUES(description), ldescription=VALUES(ldescription), storyline=VALUES(storyline), poster=VALUES(poster), poster_url=VALUES(poster_url), backdrop=VALUES(backdrop), backdrop_url=VALUES(backdrop_url), thumbnail_url=VALUES(thumbnail_url), logo_url=VALUES(logo_url), gallery_images=VALUES(gallery_images), rating=VALUES(rating), imdb_rating=VALUES(imdb_rating), trending_score=VALUES(trending_score);

DELETE FROM movie_genres WHERE movie_id BETWEEN 1001 AND 1200;
SELECT m.id, g.id FROM movies m JOIN genres g ON FIND_IN_SET(g.name, REPLACE(m.genre, ', ', ',')) > 0 WHERE m.id BETWEEN 1001 AND 1200;
